# Leet speak mappings
LEET_MAP = {
    '0': 'o', '1': 'i', '3': 'e', '4': 'a', '5': 's',
    '7': 't', '8': 'b', '9': 'g', '@': 'a', '$': 's',
    '!': 'i', '|': 'l', '+': 't', '(': 'c',
}


def normalize_homoglyphs(text: str) -> str:
    """Replace homoglyph characters with their ASCII equivalents."""
    result = []
    for char in text:
        if char in HOMOGLYPH_MAP:
            result.append(HOMOGLYPH_MAP[char])
        else:
            result.append(char)
    return ''.join(result)


def normalize_unicode(text: str) -> str:
    """Normalize Unicode to NFKD form and strip combining characters."""
    normalized = unicodedata.normalize('NFKD', text)
    # Remove combining characters (accents, diacritics used for evasion)
    stripped = ''.join(
        c for c in normalized
        if not unicodedata.combining(c)
    )
    return stripped


def decode_html_entities(text: str) -> str:
    """Decode HTML entities that might be used to obfuscate text."""
    return html.unescape(text)


def remove_zero_width_chars(text: str) -> str:
    """Remove zero-width characters used to break up spam keywords."""
    zero_width = {
        '\u200b',  # zero width space
        '\u200c',  # zero width non-joiner
        '\u200d',  # zero width joiner
        '\u2060',  # word joiner
        '\ufeff',  # zero width no-break space (BOM)
        '\u00ad',  # soft hyphen
        '\u200e',  # left-to-right mark
        '\u200f',  # right-to-left mark
        '\u202a',  # left-to-right embedding
        '\u202b',  # right-to-left embedding
        '\u202c',  # pop directional formatting
        '\u202d',  # left-to-right override
        '\u202e',  # right-to-left override
        '\u2061',  # function application
        '\u2062',  # invisible times
        '\u2063',  # invisible separator
        '\u2064',  # invisible plus
    }
    return ''.join(c for c in text if c not in zero_width)


def normalize_whitespace(text: str) -> str:
    """Collapse excessive whitespace and remove inserted spaces in words."""
    # Remove spaces between single characters (e.g., "V i a g r a" -> "Viagra")
    # Pattern: single char followed by space and single char, repeated
    text = re.sub(r'\b(\w)\s+(?=\w\b)', r'\1', text)
    # Collapse multiple whitespace
    text = re.sub(r'\s+', ' ', text)
    return text.strip()


def normalize_repeated_chars(text: str) -> str:
    """Reduce repeated characters (e.g., 'freeeeee' -> 'freee')."""
    return re.sub(r'(.)\1{2,}', r'\1\1\1', text)


def deobfuscate_leet(text: str) -> str:
    """Convert common leet speak substitutions back to letters."""
    # Only apply within word-like contexts to avoid false positives
    words = text.split()
    result = []
    for word in words:
        # If word contains mixed digits and letters, try leet decode
        has_digit = any(c.isdigit() or c in LEET_MAP for c in word)
        has_alpha = any(c.isalpha() for c in word)
        if has_digit and has_alpha:
            decoded = ''.join(LEET_MAP.get(c, c) for c in word)
            result.append(decoded)
        else:
            result.append(word)
    return ' '.join(result)


def remove_obfuscation_punctuation(text: str) -> str:
    """Remove dots/dashes/underscores inserted within words for evasion."""
    # e.g., "v.i.a.g.r.a" -> "viagra", "f-r-e-e" -> "free"
    text = re.sub(r'(?<=\w)[.\-_]{1,2}(?=\w)', '', text)
    return text


def sanitize_input(text: str, max_length: int = 50000) -> str:
    """
    Comprehensive input sanitization to prevent ML evasion attacks.
    Applies multiple normalization layers.
    """
    if not isinstance(text, str):
        raise ValueError("Input must be a string")

    # Truncate excessively long inputs (prevents DoS and buffer attacks)
    text = text[:max_length]

    # Layer 1: Remove zero-width and invisible characters
    text = remove_zero_width_chars(text)

    # Layer 2: Decode HTML entities
    text = decode_html_entities(text)

    # Layer 3: Unicode normalization
    text = normalize_unicode(text)

    # Layer 4: Homoglyph normalization
    text = normalize_homoglyphs(text)

    # Layer 5: Remove obfuscation punctuation within words
    text = remove_obfuscation_punctuation(text)

    # Layer 6: Leet speak normalization
    text = deobfuscate_leet(text)

    # Layer 7: Normalize repeated characters
    text = normalize_repeated_chars(text)

    # Layer 8: Normalize whitespace (including spaced-out words)
    text = normalize_whitespace(text)

    # Layer 9: Lowercase
    text = text.lower()

    # Layer 10: Remove non-printable characters
    text = ''.join(c for c in text if c.isprintable() or c in ('\n', '\t'))

    return text


