def extract_structural_features(raw_text: str) -> dict:
    """
    Extract structural/statistical features from the RAW text
    that are harder to evade than word-based features alone.
    """
    features = {}

    # Ratio of uppercase characters
    alpha_chars = [c for c in raw_text if c.isalpha()]
    if alpha_chars:
        features['uppercase_ratio'] = sum(1 for c in alpha_chars if c.isupper()) / len(alpha_chars)
    else:
        features['uppercase_ratio'] = 0.0

    # Ratio of special characters
    if len(raw_text) > 0:
        features['special_char_ratio'] = sum(1 for c in raw_text if not c.isalnum() and not c.isspace()) / len(raw_text)
    else:
        features['special_char_ratio'] = 0.0

    # Ratio of digits
    if len(raw_text) > 0:
        features['digit_ratio'] = sum(1 for c in raw_text if c.isdigit()) / len(raw_text)
    else:
        features['digit_ratio'] = 0.0

    # Number of URLs
    features['url_count'] = len(re.findall(r'https?://\S+|www\.\S+', raw_text, re.IGNORECASE))

    # Number of email addresses
    features['email_count'] = len(re.findall(r'\S+@\S+\.\S+', raw_text))

    # Exclamation mark density
    if len(raw_text) > 0:
        features['exclamation_density'] = raw_text.count('!') / len(raw_text)
    else:
        features['exclamation_density'] = 0.0

    # Dollar sign count (common in spam)
    features['dollar_count'] = raw_text.count('$')

    # Number of non-ASCII characters (potential homoglyph attack indicator)
    features['non_ascii_ratio'] = sum(1 for c in raw_text if ord(c) > 127) / max(len(raw_text), 1)

    # Zero-width character count (evasion indicator)
    zero_width_chars = {'\u200b', '\u200c', '\u200d', '\u2060', '\ufeff', '\u00ad'}
    features['zero_width_count'] = sum(1 for c in raw_text if c in zero_width_chars)

    # Average word length
    words = raw_text.split()
    if words:
        features['avg_word_length'] = np.mean([len(w) for w in words])
    else:
        features['avg_word_length'] = 0.0

    # Text length
    features['text_length'] = min(len(raw_text), 50000)  # cap for safety

    # Entropy of character distribution (obfuscated text often has unusual entropy)
    if len(raw_text) > 0:
        char_counts = Counter(raw_text)
        total = len(raw_text)
        entropy = -sum((count / total) * np.log2(count / total) for count in char_counts.values())
        features['char_entropy'] = entropy
    else:
        features['char_entropy'] = 0.0

    return features


