class SpamDetector:
    """Spam detection model with anti-evasion preprocessing."""

    STRUCTURAL_FEATURE_NAMES = [
        'uppercase_ratio', 'special_char_ratio', 'digit_ratio',
        'url_count', 'email_count', 'exclamation_density',
        'dollar_count', 'non_ascii_ratio', 'zero_width_count',
        'avg_word_length', 'text_length', 'char_entropy'
    ]

    def __init__(self):
        self.tfidf_vectorizer = TfidfVectorizer(
            max_features=5000,
            ngram_range=(1, 2),  # unigrams and bigrams
            min_df=1,
            max_df=0.95,
            sublinear_tf=True,
            strip_accents='unicode',
        )
        self.model = LogisticRegression(
            C=1.0,
            max_iter=1000,
            class_weight='balanced',  # handle class imbalance
            solver='lbfgs',
            random_state=42,
        )
        self.is_trained = False

    def _preprocess_for_tfidf(self, raw_texts: list) -> list:
        """Apply anti-evasion sanitization before TF-IDF."""
        return [sanitize_input(text) for text in raw_texts]

    def _extract_structural_features_batch(self, raw_texts: list) -> np.ndarray:
        """Extract structural features from raw (unsanitized) texts."""
        features_list = []
        for text in raw_texts:
            feats = extract_structural_features(text)
            features_list.append([feats[name] for name in self.STRUCTURAL_FEATURE_NAMES])
        return np.array(features_list)

    def _build_feature_matrix(self, raw_texts: list, fit_tfidf: bool = False) -> np.ndarray:
        """Combine TF-IDF features with structural features."""
        # Sanitized text for TF-IDF
        sanitized = self._preprocess_for_tfidf(raw_texts)

        if fit_tfidf:
            tfidf_features = self.tfidf_vectorizer.fit_transform(sanitized)
        else:
            tfidf_features = self.tfidf_vectorizer.transform(sanitized)

        # Structural features from raw text
        structural_features = self._extract_structural_features_batch(raw_texts)

        # Combine
        from scipy.sparse import hstack, csr_matrix
        structural_sparse = csr_matrix(structural_features)
        combined = hstack([tfidf_features, structural_sparse])

        return combined

    def train(self, texts: list, labels: list):
        """Train the spam detection model."""
        X = self._build_feature_matrix(texts, fit_tfidf=True)
        y = np.array(labels)

        self.model.fit(X, y)
        self.is_trained = True

        # Evaluate on training data
        y_pred = self.model.predict(X)
        print("Training Classification Report:")
        print(classification_report(y, y_pred, target_names=['ham', 'spam']))

    def predict(self, text: str) -> dict:
        """Predict spam probability for a single email."""
        if not self.is_trained:
            raise RuntimeError("Model has not been trained yet.")

        X = self._build_feature_matrix([text], fit_tfidf=False)
        proba = self.model.predict_proba(X)[0]
        prediction = self.model.predict(X)[0]

        # Confidence calibration: flag if structural features indicate evasion
        structural_feats = extract_structural_features(text)
        evasion_indicators = []

        if structural_feats['zero_width_count'] > 0:
            evasion_indicators.append('zero_width_characters_detected')
        if structural_feats['non_ascii_ratio'] > 0.1:
            evasion_indicators.append('high_non_ascii_ratio')

        # Compare raw vs sanitized text similarity
        sanitized = sanitize_input(text)
        raw_lower = text.lower().strip()
        if len(raw_lower) > 0:
            # Levenshtein-like difference ratio
            diff_ratio = 1.0 - (len(set(sanitized) & set(raw_lower)) / max(len(set(sanitized) | set(raw_lower)), 1))
            if diff_ratio > 0.3:
                evasion_indicators.append('significant_normalization_difference')

        result = {
            'spam_probability': float(proba[1]),
            'ham_probability': float(proba[0]),
            'is_spam': bool(prediction == 1),
            'confidence': float(max(proba)),
            'label': 'spam' if prediction == 1 else 'ham',
        }

        if evasion_indicators:
            result['evasion_warning'] = evasion_indicators
            # Boost spam probability slightly if evasion is detected
            # (legitimate emails rarely use these techniques)
            evasion_boost = min(0.15 * len(evasion_indicators), 0.3)
            adjusted_spam_prob = min(result['spam_probability'] + evasion_boost, 1.0)
            result['adjusted_spam_probability'] = adjusted_spam_prob
            if adjusted_spam_prob > 0.5:
                result['is_spam'] = True
                result['label'] = 'spam'

        return result

    def save(self, filepath: str):
        """Save the trained model to disk."""
        with open(filepath, 'wb') as f:
            pickle.dump({
                'tfidf_vectorizer': self.tfidf_vectorizer,
                'model': self.model,
                'is_trained': self.is_trained,
            }, f)

    def load(self, filepath: str):
        """Load a trained model from disk."""
        with open(filepath, 'rb') as f:
            data = pickle.load(f)
            self.tfidf_vectorizer = data['tfidf_vectorizer']
            self.model = data['model']
            self.is_trained = data['is_trained']


