def require_api_key(f):
    """Decorator to require API key authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        api_key = request.headers.get('X-API-Key', '')
        key_hash = hashlib.sha256(api_key.encode()).hexdigest()
        if key_hash not in API_KEYS:
            return jsonify({
                'error': 'Unauthorized',
                'message': 'Valid API key required in X-API-Key header'
            }), 401
        return f(*args, **kwargs)
    return decorated


def check_rate_limit(f):
    """Decorator to enforce rate limiting."""
    @wraps(f)
    def decorated(*args, **kwargs):
        client_ip = request.remote_addr or 'unknown'
        if not rate_limiter.is_allowed(client_ip):
            return jsonify({
                'error': 'Rate limit exceeded',
                'message': 'Too many requests. Please try again later.'
            }), 429
        return f(*args, **kwargs)
    return decorated


@app.route('/api/v1/predict', methods=['POST'])
@check_rate_limit
@require_api_key
def predict_spam():
    """
    Predict whether an email is spam.

    Request body (JSON):
        {
            "email_text": "Your email content here"
        }

    Response (JSON):
        {
            "spam_probability": 0.95,
            "ham_probability": 0.05,
            "is_spam": true,
            "confidence": 0.95,
            "label": "spam"
        }
    """
    if not request.is_json:
        return jsonify({
            'error': 'Bad Request',
            'message': 'Content-Type must be application/json'
        }), 400

    data = request.get_json(silent=True)
    if data is None:
        return jsonify({
            'error': 'Bad Request',
            'message': 'Invalid JSON body'
        }), 400

    email_text = data.get('email_text', '')

    if not isinstance(email_text, str):
        return jsonify({
            'error': 'Bad Request',
            'message': 'email_text must be a string'
        }), 400

    if len(email_text) == 0:
        return jsonify({
            'error': 'Bad Request',
            'message': 'email_text cannot be empty'
        }), 400

    if len(email_text) > 100000:
        return jsonify({
            'error': 'Bad Request',
            'message': 'email_text exceeds maximum length of 100,000 characters'
        }), 400

    try:
        result = detector.predict(email_text)
        return jsonify(result), 200
    except Exception as e:
        return jsonify({
            'error': 'Internal Server Error',
            'message': 'An error occurred during prediction'
        }), 500


